import React, { useState } from "react";
import { useNavigate } from "react-router-dom";
import "../../pages/professor/Home.css";
import Title from "../../components/title/Title";
import Header from "../../components/header/Header";
import Input from "../../components/input/Input";
import Button from "../../components/button/Button";
import axios from "axios";

const Login = () => {
  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");
  const [error, setError] = useState(""); // Estado para erros
  const navigate = useNavigate();

  const handleLogin = async (e) => {
    e.preventDefault();
    try {
      const response = await axios.get("http://localhost:8080/Professor/login", {
        email: email,
        password: password,
      });
      console.log("Login Successful:", response.data);
      
      // Redireciona para a rota desejada após login bem-sucedido
      navigate("/workshops");
    } catch (err) {
      console.error(err);
      setError("Login falhou. Verifique suas credenciais."); // Define o erro
    }
  };

  return (
    <div className="page">
      <Header title="CADASTRO" />
      <div className="content login">
        <Title text="LOGIN" fontSize="3.5rem" margin="0px" />
        <p className="text">Faça login para utilizar a plataforma</p>
        <div className="inputs">
          <form onSubmit={handleLogin}>
            <p className="text no-width">Email</p>
            <Input
              type="text"
              placeholder="Digite seu e-mail"
              value={email}
              onChange={(e) => setEmail(e.target.value)}
              customStyle={{
                marginBottom: "10px",
                padding: "10px",
                fontSize: "16px",
              }}
            />
            <p className="text no-width">Senha</p>
            <Input
              type="password"
              placeholder="Digite sua senha"
              value={password}
              onChange={(e) => setPassword(e.target.value)}
              customStyle={{
                marginBottom: "10px",
                padding: "10px",
                fontSize: "16px",
              }}
            />
            {error && <p style={{ color: "red" }}>{error}</p>} {/* Exibe mensagem de erro */}
            <Button text="ENTRAR" type="submit" /> {/* Define o tipo como "submit" */}
          </form>
        </div>
      </div>
    </div>
  );
};

export default Login;
